pygame.init()
screen = pygame.display.set_mode((600, 700))



def locate_cell_corners(row, col):
        cell_size = 20
        offset_x = 20
        offset_y = 20
        x = offset_x + col * cell_size # we start at the offset coords:(20,20) + the number of cells we have to move to the right (col) * the size of each cell
        y = offset_y + row * cell_size #the same for row but we move down instead of right
        return x, y

def test_visited():
    for i in visited:
        x,y = i[0], i[1]
        pygame.draw.rect(screen, (0,0,0), (x + 1, y + 1, 20 - 2, 20 - 2))

if __name__ == "__main__":
    running = True
    while running:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
        test_visited()
        pygame.display.flip() # this is needed to update the display after drawing the rectangles
    pygame.quit()
